{"content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

class SpacingAroundColonRuleAnnotationTest {
    private val spacingAroundColonRuleAssertThat = assertThatRule { SpacingAroundColonRule() }

    @Test
    fun `Given spacing around colon in annotation use-site target`() {
        val code =
            """
            @file :JvmName("Foo")
            @file: JvmName("Foo")
            @file : JvmName("Foo")

            @set :[Inject VisibleForTesting]
            @set: [Inject VisibleForTesting]
            @set : [Inject VisibleForTesting]
            """.trimIndent()
        val formattedCode =
            """
            @file:JvmName("Foo")
            @file:JvmName("Foo")
            @file:JvmName("Foo")

            @set:[Inject VisibleForTesting]
            @set:[Inject VisibleForTesting]
            @set:[Inject VisibleForTesting]
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(1, 7, "Unexpected spacing before \":\""),
                LintViolation(2, 7, "Unexpected spacing after \":\""),
                LintViolation(3, 7, "Unexpected spacing before \":\""),
                LintViolation(3, 9, "Unexpected spacing after \":\""),
                LintViolation(5, 6, "Unexpected spacing before \":\""),
                LintViolation(6, 6, "Unexpected spacing after \":\""),
                LintViolation(7, 6, "Unexpected spacing before \":\""),
                LintViolation(7, 8, "Unexpected spacing after \":\""),
            )
            .isFormattedAs(formattedCode)
    }
}
