 18→import com.pinterest.ktlint.ruleset.standard.StandardRule
 19→import org.jetbrains.kotlin.com.intellij.lang.ASTNode
 20→import org.jetbrains.kotlin.com.intellij.psi.impl.source.tree.LeafPsiElement
 21→import org.jetbrains.kotlin.psi.KtBlockExpression
 22→import org.jetbrains.kotlin.psi.KtClassOrObject
 23→import org.jetbrains.kotlin.psi.KtConstructor
 24→import org.jetbrains.kotlin.psi.KtNamedFunction
 25→import org.jetbrains.kotlin.psi.KtProperty
 26→import org.jetbrains.kotlin.psi.KtTypeConstraint
 27→import org.jetbrains.kotlin.psi.KtTypeParameterList
 28→import org.jetbrains.kotlin.psi.psiUtil.siblings
 29→import org.jetbrains.kotlin.utils.addToStdlib.firstIsInstanceOrNull
 30→
 31→public class SpacingAroundColonRule : StandardRule("colon-spacing") {
 32→    override fun beforeVisitChildNodes(
 33→        node: ASTNode,
 34→        autoCorrect: Boolean,
 35→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 36→    ) {
 37→        if (node.elementType == COLON) {
 38→            val psiParent = node.psi.parent
 39→            val prevLeaf = node.prevLeaf()
 40→            if (prevLeaf != null && prevLeaf.isWhiteSpaceWithNewline()) {
 41→                emit(prevLeaf.startOffset, "Unexpected newline before \":\"", true)
 42→                if (autoCorrect) {
 43→                    val prevNonCodeElements =
 44→                        node
 45→                            .siblings(forward = false)
 46→                            .takeWhile { it.isWhiteSpace() || it.isPartOfComment() }
 47→                            .toList()
 48→                            .reversed()
 49→                    when {
 50→                        psiParent is KtProperty || psiParent is KtNamedFunction -> {
 51→                            val equalsSignElement =
 52→                                node
 53→                                    .siblings(forward = true)
 54→                                    .firstOrNull { it.elementType == EQ }
 55→                            if (equalsSignElement != null) {
 56→                                equalsSignElement
 57→                                    .treeNext
 58→                                    ?.let { treeNext ->
 59→                                        prevNonCodeElements.forEach {
 60→                                            node.treeParent.addChild(it, treeNext)
 61→                                        }
 62→                                        if (treeNext.isWhiteSpace()) {
 63→                                            equalsSignElement.treeParent.removeChild(treeNext)
 64→                                        }
 65→                                        Unit
 66→                                    }
 67→                            }
 68→                            val blockElement =
 69→                                node
 70→                                    .siblings(forward = true)
 71→                                    .firstIsInstanceOrNull<KtBlockExpression>()
 72→                            if (blockElement != null) {
 73→                                val before =
 74→                                    blockElement
 75→                                        .firstChildNode
 76→                                        .nextSibling()
 77→                                prevNonCodeElements
 78→                                    .let {
 79→                                        if (it.first().isWhiteSpace()) {
 80→                                            blockElement.treeParent.removeChild(it.first())
 81→                                            it.drop(1)
 82→                                        }
 83→                                        if (it.last().isWhiteSpaceWithNewline()) {
 84→                                            blockElement.treeParent.removeChild(it.last())
 85→                                            it.dropLast(1)
 86→                                        } else {
 87→                                            it
 88→                                        }
 89→                                    }.forEach {
 90→                                        blockElement.addChild(it, before)
 91→                                    }
 92→                            }
 93→                        }
 94→                        prevLeaf.prevLeaf()?.isPartOfComment() == true -> {
 95→                            val nextLeaf = node.nextLeaf()
 96→                            prevNonCodeElements.forEach {
 97→                                node.treeParent.addChild(it, nextLeaf)
 98→                            }
 99→                            if (nextLeaf != null && nextLeaf.isWhiteSpace()) {
100→                                node.treeParent.removeChild(nextLeaf)
101→                            }
102→                        }
103→                        else -> {
104→                            val text = prevLeaf.text
105→                            if (node.removeSpacingBefore) {
106→                                prevLeaf.treeParent.removeChild(prevLeaf)
107→                            } else {
108→                                (prevLeaf as LeafPsiElement).rawReplaceWithText(" ")
109→                            }
110→                            if (!node.removeSpacingAfter) {
111→                                node.upsertWhitespaceAfterMe(text)
112→                            }
113→                        }
114→                    }
115→                }
116→            }
117→            if (node.prevSibling().isWhiteSpace() && node.removeSpacingBefore && !prevLeaf.isWhiteSpaceWithNewline()) {
118→                emit(node.startOffset, "Unexpected spacing before \":\"", true)
119→                if (autoCorrect) {
120→                    node
121→                        .prevSibling()
122→                        ?.let { prevSibling ->
123→                            prevSibling.treeParent.removeChild(prevSibling)
124→                        }
125→                }
126→            }
127→            val missingSpacingBefore =
128→                !node.prevSibling().isWhiteSpace() &&
129→                    (
130→                        psiParent is KtClassOrObject || psiParent is KtConstructor<*> ||
131→                            psiParent is KtTypeConstraint || psiParent.parent is KtTypeParameterList
132→                        )
133→            val missingSpacingAfter = !node.nextSibling().isWhiteSpace() && !node.removeSpacingAfter
134→            when {
135→                missingSpacingBefore && missingSpacingAfter -> {
136→                    emit(node.startOffset, "Missing spacing around \":\"", true)
137→                    if (autoCorrect) {
138→                        node.upsertWhitespaceBeforeMe(" ")
139→                        node.upsertWhitespaceAfterMe(" ")
140→                    }
141→                }
142→                missingSpacingBefore -> {
143→                    emit(node.startOffset, "Missing spacing before \":\"", true)
144→                    if (autoCorrect) {
145→                        node.upsertWhitespaceBeforeMe(" ")
146→                    }
147→                }
148→                missingSpacingAfter -> {
149→                    emit(node.startOffset + 1, "Missing spacing after \":\"", true)
150→                    if (autoCorrect) {
151→                        node.upsertWhitespaceAfterMe(" ")
152→                    }
153→                }
154→            }
155→            if (node.removeSpacingAfter && node.nextSibling().isWhiteSpace()) {
156→                emit(node.startOffset + 1, "Unexpected spacing after \":\"", true)
157→                if (autoCorrect) {
158→                    node
159→                        .nextSibling()
160→                        ?.let { nextSibling ->
161→                            nextSibling.treeParent.removeChild(nextSibling)
162→                        }
163→                }
164→            }
165→        }
166→    }
167→
168→    private inline val ASTNode.removeSpacingBefore: Boolean
169→        get() =
170→            psi
171→                .parent
172→                .let { psiParent ->
173→                    psiParent !is KtClassOrObject &&
174→                        psiParent !is KtConstructor<*> && // constructor : this/super
175→                        psiParent !is KtTypeConstraint && // where T : S
176→                        psiParent?.parent !is KtTypeParameterList
177→                }
178→
179→    private inline val ASTNode.removeSpacingAfter: Boolean
180→        get() = isPartOf(ANNOTATION) || isPartOf(ANNOTATION_ENTRY)
181→}
182→
183→public val SPACING_AROUND_COLON_RULE_ID: RuleId = SpacingAroundColonRule().ruleId
184→
